&lt;ul&gt;
&lt;li style=&quot;font-size: 16px;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;Medical, dental and vision insurance&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 16px;&quot;&gt;&lt;span style=&quot;font-

